mapper.sql:
WHERE machine.is_active != 2

      AND machine.hospital_id = #{hospitalId}


      AND machine.modality_id = #{request.modalityId}


      AND (
          COALESCE(machine.machine_name, '') ILIKE '%' || #{request.searchText} || '%'
          OR COALESCE(machine.machine_ae_title, '') ILIKE '%' || #{request.searchText} || '%'
          OR COALESCE(machine.machine_host, '') ILIKE '%' || #{request.searchText} || '%'
          OR COALESCE(m.name, '') ILIKE '%' || #{request.searchText} || '%'
          OR COALESCE(h.name, '') ILIKE '%' || #{request.searchText} || '%'
      )

WHERE s.is_active != 2
AND s.hospital_id = #{hospitalId}
AND ( s.name ILIKE '%' || #{filter.searchText} || '%' OR s.ip_address ILIKE '%' || #{filter.searchText} || '%' OR s.port::text ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(s.dicom_port, 4242)::text ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(s.viewer_base_url, '') ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(s.pacs_api_callback_base_url, '') ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(s.ae_title, '') ILIKE '%' || #{filter.searchText} || '%' )

mapper.select:
SELECT s.id AS id, s.public_id::text AS publicKey, s.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.name AS hospitalName, s.name AS name, s.ip_address AS ipAddress, s.port AS port, s.dicom_port AS dicomPort, s.ae_title AS aeTitle,
s.public_health_check_url AS publicHealthCheckUrl, s.viewer_base_url AS viewerBaseUrl, s.pacs_api_callback_base_url AS pacsApiCallbackBaseUrl, s.username AS username, (s.password IS NOT NULL AND BTRIM(s.password) != '') AS hasPassword, s.password AS password,
STRING_AGG(DISTINCT route_info.modality_id::text, ',' ORDER BY route_info.modality_id::text) AS modalityIdCsv, STRING_AGG(DISTINCT route_modality.public_id::text, ',' ORDER BY route_modality.public_id::text) AS modalityPublicKeyCsv, STRING_AGG(DISTINCT route_modality.name, ',' ORDER BY route_modality.name) AS modalityNameCsv, s.is_active AS isActive, TO_CHAR(s.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, TO_CHAR(s.modified_at, 'YYYY-MM-DD HH24:MI:SS') AS modifiedAt FROM hospital_dicom_servers s INNER JOIN hospitals h ON h.id = s.hospital_id
WHERE s.id = #{id}
AND s.hospital_id = #{hospitalId}
AND s.is_active != 2 GROUP BY s.id, h.id LIMIT 1

SELECT COUNT(1)
FROM hospital_dicom_servers
WHERE hospital_id = #{hospitalId}
  AND is_active = 1
  AND LOWER(name) = LOWER(#{name})

    AND id != #{excludeId}

SELECT COUNT(1)
FROM hospital_dicom_servers
WHERE hospital_id = #{hospitalId}
  AND is_active = 1
  AND LOWER(ip_address) = LOWER(#{ipAddress})
  AND port = #{port}
  AND COALESCE(dicom_port, 4242) = COALESCE(#{dicomPort}, 4242)
  AND LOWER(COALESCE(ae_title, '')) = LOWER(COALESCE(#{aeTitle}, ''))

    AND id != #{excludeId}

SELECT COUNT(DISTINCT id)
FROM hospital_dicom_servers
WHERE hospital_id = #{hospitalId}
  AND is_active = 1
  AND id IN

    #{serverId}

SELECT
FROM hospital_dicom_machines machine INNER JOIN hospitals h ON h.id = machine.hospital_id INNER JOIN modalities m ON m.id = machine.modality_id WHERE machine.id = #{id}
AND machine.hospital_id = #{hospitalId}
AND machine.is_active != 2 LIMIT 1

SELECT COUNT(1)
FROM hospital_dicom_machines
WHERE hospital_id = #{hospitalId}
  AND modality_id = #{modalityId}
  AND LOWER(machine_ae_title) = LOWER(#{machineAeTitle})
  AND LOWER(machine_host) = LOWER(#{machineHost})
  AND machine_port = #{machinePort}
  AND is_active = 1

    AND id != #{excludeId}

SELECT COUNT(1)
FROM hospital_modality_server_routes
WHERE hospital_id = #{hospitalId}
  AND machine_id = #{machineId}

mapper.sql:
WHERE r.hospital_id = #{hospitalId} AND r.is_active != 2
AND r.modality_id = #{request.modalityId}
AND ( COALESCE(s.name, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(s.ip_address, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(s.viewer_base_url, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(s.ae_title, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(machine.machine_name, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(machine.machine_ae_title, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(machine.machine_host, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(m.name, '') ILIKE '%' || #{request.searchText} || '%' OR COALESCE(h.name, '') ILIKE '%' || #{request.searchText} || '%' )

mapper.select:
SELECT cfg.id AS id, cfg.public_id::text AS publicKey, cfg.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.name AS hospitalName, cfg.dicom_server_id AS dicomServerId, cfg_server.public_id::text AS dicomServerPublicKey, cfg_server.name AS dicomServerName, COUNT(DISTINCT route_summary.id)::bigint AS routeCount, COUNT(DISTINCT route_summary.modality_id)::bigint AS modalityCount, CASE WHEN cfg.dicom_server_id IS NULL THEN 0::bigint ELSE 1::bigint END AS dicomServerCount, STRING_AGG(DISTINCT route_summary.modality_id::text, ',' ORDER BY route_summary.modality_id::text) AS modalityIdCsv, STRING_AGG(DISTINCT modality_summary.public_id::text, ',' ORDER BY modality_summary.public_id::text) AS modalityPublicKeyCsv, STRING_AGG(DISTINCT modality_summary.name, '~|~' ORDER BY modality_summary.name) AS modalityNameCsv, cfg.dicom_server_id::text AS dicomServerIdCsv, cfg_server.public_id::text AS dicomServerPublicKeyCsv, cfg_server.name AS dicomServerNameCsv, (CASE WHEN cfg_server.ssl_enabled IS TRUE THEN 'https' ELSE 'http' END || '://' || cfg_server.ip_address || ':' || cfg_server.port) AS dicomServerBaseUrlCsv, cfg_server.ae_title AS aeTitleCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_name, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_name, '')) AS machineNameCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_ae_title, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_ae_title, '')) AS machineAeTitleCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_host, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_host, '')) AS machineHostCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_port::text, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_port::text, '')) AS machinePortCsv, cfg.is_active AS isActive, TO_CHAR(cfg.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, TO_CHAR(cfg.modified_at, 'YYYY-MM-DD HH24:MI:SS') AS modifiedAt FROM hospital_dicom_routing_configs cfg INNER JOIN hospitals h ON h.id = cfg.hospital_id LEFT JOIN hospital_dicom_servers cfg_server ON cfg_server.id = cfg.dicom_server_id AND cfg_server.hospital_id = cfg.hospital_id LEFT JOIN hospital_modality_server_routes route_summary ON route_summary.routing_config_id = cfg.id AND route_summary.hospital_id = cfg.hospital_id AND route_summary.is_active = 1 LEFT JOIN modalities modality_summary ON modality_summary.id = route_summary.modality_id LEFT JOIN hospital_dicom_machines machine_summary ON machine_summary.id = route_summary.machine_id
GROUP BY cfg.id, cfg.hospital_id, h.name, h.public_id, cfg.dicom_server_id, cfg_server.id, cfg_server.name, cfg_server.ssl_enabled, cfg_server.ip_address, cfg_server.port, cfg_server.ae_title, cfg.is_active, cfg.created_at, cfg.modified_at ORDER BY cfg.id DESC
LIMIT #{request.rowsPerPage} OFFSET #{request.page}

SELECT cfg.id AS id, cfg.public_id::text AS publicKey, cfg.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.name AS hospitalName, cfg.dicom_server_id AS dicomServerId, cfg_server.public_id::text AS dicomServerPublicKey, cfg_server.name AS dicomServerName, COUNT(DISTINCT route_summary.id)::bigint AS routeCount, COUNT(DISTINCT route_summary.modality_id)::bigint AS modalityCount, CASE WHEN cfg.dicom_server_id IS NULL THEN 0::bigint ELSE 1::bigint END AS dicomServerCount, STRING_AGG(DISTINCT route_summary.modality_id::text, ',' ORDER BY route_summary.modality_id::text) AS modalityIdCsv, STRING_AGG(DISTINCT modality_summary.public_id::text, ',' ORDER BY modality_summary.public_id::text) AS modalityPublicKeyCsv, STRING_AGG(DISTINCT modality_summary.name, '~|~' ORDER BY modality_summary.name) AS modalityNameCsv, cfg.dicom_server_id::text AS dicomServerIdCsv, cfg_server.public_id::text AS dicomServerPublicKeyCsv, cfg_server.name AS dicomServerNameCsv, (CASE WHEN cfg_server.ssl_enabled IS TRUE THEN 'https' ELSE 'http' END || '://' || cfg_server.ip_address || ':' || cfg_server.port) AS dicomServerBaseUrlCsv, cfg_server.ae_title AS aeTitleCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_name, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_name, '')) AS machineNameCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_ae_title, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_ae_title, '')) AS machineAeTitleCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_host, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_host, '')) AS machineHostCsv, STRING_AGG(DISTINCT COALESCE(machine_summary.machine_port::text, ''), '~|~' ORDER BY COALESCE(machine_summary.machine_port::text, '')) AS machinePortCsv, cfg.is_active AS isActive, TO_CHAR(cfg.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, TO_CHAR(cfg.modified_at, 'YYYY-MM-DD HH24:MI:SS') AS modifiedAt FROM hospital_dicom_routing_configs cfg INNER JOIN hospitals h ON h.id = cfg.hospital_id LEFT JOIN hospital_dicom_servers cfg_server ON cfg_server.id = cfg.dicom_server_id AND cfg_server.hospital_id = cfg.hospital_id LEFT JOIN hospital_modality_server_routes route_summary ON route_summary.routing_config_id = cfg.id AND route_summary.hospital_id = cfg.hospital_id AND route_summary.is_active = 1 LEFT JOIN modalities modality_summary ON modality_summary.id = route_summary.modality_id LEFT JOIN hospital_dicom_machines machine_summary ON machine_summary.id = route_summary.machine_id WHERE cfg.id = #{id}
AND cfg.hospital_id = #{hospitalId}
AND cfg.is_active != 2 GROUP BY cfg.id, cfg.hospital_id, h.name, h.public_id, cfg.dicom_server_id, cfg_server.id, cfg_server.name, cfg_server.ssl_enabled, cfg_server.ip_address, cfg_server.port, cfg_server.ae_title, cfg.is_active, cfg.created_at, cfg.modified_at LIMIT 1

SELECT COUNT(1)
FROM hospital_dicom_routing_configs
WHERE hospital_id = #{hospitalId}
  AND dicom_server_id = #{dicomServerId}
  AND is_active = 1

    AND id != #{excludeId}

SELECT r.id AS id, r.public_id::text AS publicKey, r.routing_config_id AS routingConfigId, cfg.public_id::text AS routingConfigPublicKey, r.machine_id AS machineId, machine.public_id::text AS machinePublicKey, r.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.name AS hospitalName, r.modality_id AS modalityId, m.public_id::text AS modalityPublicKey, m.name AS modalityName, m.abbr AS modalityAbbr, cfg.dicom_server_id AS dicomServerId, s.public_id::text AS dicomServerPublicKey, s.name AS dicomServerName, machine.machine_name AS machineName, machine.machine_ae_title AS machineAeTitle, machine.machine_host AS machineHost, machine.machine_port AS machinePort, s.ip_address AS ipAddress, s.port AS port, s.dicom_port AS dicomPort, s.ae_title AS aeTitle,
s.viewer_base_url AS viewerBaseUrl, s.pacs_api_callback_base_url AS pacsApiCallbackBaseUrl, s.username AS username, (s.password IS NOT NULL AND BTRIM(s.password) != '') AS hasPassword, s.password AS password,
r.is_active AS isActive FROM hospital_modality_server_routes r INNER JOIN hospital_dicom_routing_configs cfg ON cfg.id = r.routing_config_id AND cfg.hospital_id = r.hospital_id AND cfg.is_active = 1 INNER JOIN hospitals h ON h.id = r.hospital_id INNER JOIN modalities m ON m.id = r.modality_id INNER JOIN hospital_dicom_servers s ON s.id = cfg.dicom_server_id INNER JOIN hospital_dicom_machines machine ON machine.id = r.machine_id WHERE r.is_active = 1
AND r.hospital_id = #{hospitalId}
AND r.routing_config_id IN
#{routingConfigId}
AND r.modality_id = #{modalityId}
ORDER BY r.routing_config_id ASC, m.name ASC, s.name ASC, r.id ASC
